content:
{
  "sentences": [
    {
      "text": "我想預約看診，請問明天上午有空嗎？",
      "pinyin": "Wǒ xiǎng yùyuē kànzhěn, qǐngwèn míngtiān shàngwǔ yǒu kòng ma?",
      "pinyin_numeric": "wo3 xiang3 yu4yue1 kan4zhen3, qing3wen4 ming2tian1 shang4wu3 you3 kong4 ma0?",
      "translation_en": "I'd like to make an appointment to see the doctor. Do you have availability tomorrow morning?",
      "translation_ko": "진료 예약을 하고 싶은데요, 내일 오전에 시간이 있나요?"
    },
    {
      "text": "我想訂位，請問今天晚上還有座位嗎？",
      "pinyin": "Wǒ xiǎng dìngwèi, qǐngwèn jīntiān wǎnshàng hái yǒu zuòwèi ma?",
      "pinyin_numeric": "wo3 xiang3 ding4wei4, qing3wen4 jin1tian1 wan3shang4 hai2 you3 zuo4wei4 ma0?",
      "translation_en": "I'd like to make a reservation. Do you still have seats available tonight?",
      "translation_ko": "예약을 하고 싶은데요, 오늘 저녁에 자리가 있나요?"
    },
    {
      "text": "我想外帶兩份牛肉麵，請問要等多久？",
      "pinyin": "Wǒ xiǎng wàidài liǎng fèn niúròumiàn, qǐngwèn yào děng duōjiǔ?",
      "pinyin_numeric": "wo3 xiang3 wai4dai4 liang3 fen4 niu2rou4mian4, qing3wen4 yao4 deng3 duo1jiu3?",
      "translation_en": "I'd like to order two portions of beef noodles for takeout. How long will it take?",
      "translation_ko": "소고기 국수 두 인분을 포장하고 싶은데요, 얼마나 기다려야 하나요?"
    },
    {
      "text": "我想請問你們的營業時間，請問今天有休息嗎？",
      "pinyin": "Wǒ xiǎng qǐngwèn nǐmen de yíngyè shíjiān, qǐngwèn jīntiān yǒu xiūxi ma?",
      "pinyin_numeric": "wo3 xiang3 qing3wen4 ni3men de ying2ye4 shi2jian1, qing3wen4 jin1tian1 you3 xiu1xi ma0?",
      "translation_en": "I'd like to ask about your business hours. Are you closed today?",
      "translation_ko": "영업 시간을 여쭤보고 싶은데요, 오늘 쉬시나요?"
    },
    {
      "text": "我想找王小姐，請問她在嗎？",
      "pinyin": "Wǒ xiǎng zhǎo Wáng xiǎojiě, qǐngwèn tā zài ma?",
      "pinyin_numeric": "wo3 xiang3 zhao3 Wang2 xiao3jie3, qing3wen4 ta1 zai4 ma0?",
      "translation_en": "I'd like to speak with Miss Wang. Is she available?",
      "translation_ko": "왕 씨를 찾고 있는데요, 계신가요?"
    },
    {
      "text": "我想外送，請問可以送到這個地址嗎？",
      "pinyin": "Wǒ xiǎng wàisòng, qǐngwèn kěyǐ sòng dào zhège dìzhǐ ma?",
      "pinyin_numeric": "wo3 xiang3 wai4song4, qing3wen4 ke3yi3 song4 dao4 zhe4ge di4zhi3 ma0?",
      "translation_en": "I'd like to order delivery. Can you deliver to this address?",
      "translation_ko": "배달을 하고 싶은데요, 이 주소로 배송 가능한가요?"
    },
    {
      "text": "我想掛號，請問下午還有名額嗎？",
      "pinyin": "Wǒ xiǎng guàhào, qǐngwèn xiàwǔ hái yǒu míng'é ma?",
      "pinyin_numeric": "wo3 xiang3 gua4hao4, qing3wen4 xia4wu3 hai2 you3 ming2e2 ma0?",
      "translation_en": "I'd like to register for an appointment. Are there any slots available this afternoon?",
      "translation_ko": "접수를 하고 싶은데요, 오후에 자리가 있나요?"
    },
    {
      "text": "我想請問你們有賣珍珠奶茶嗎？",
      "pinyin": "Wǒ xiǎng qǐngwèn nǐmen yǒu mài zhēnzhū nǎichá ma?",
      "pinyin_numeric": "wo3 xiang3 qing3wen4 ni3men you3 mai4 zhen1zhu1 nai3cha2 ma0?",
      "translation_en": "I'd like to ask if you sell bubble milk tea.",
      "translation_ko": "버블 밀크티를 파시나요?"
    },
    {
      "text": "我想訂位，請問明天晚上六點有兩個人的位子嗎？",
      "pinyin": "Wǒ xiǎng dìngwèi, qǐngwèn míngtiān wǎnshàng liù diǎn yǒu liǎng ge rén de wèizi ma?",
      "pinyin_numeric": "wo3 xiang3 ding4wei4, qing3wen4 ming2tian1 wan3shang4 liu4 dian3 you3 liang3 ge ren2 de wei4zi ma0?",
      "translation_en": "I'd like to make a reservation. Do you have a table for two tomorrow at 6 PM?",
      "translation_ko": "예약을 하고 싶은데요, 내일 저녁 6시에 두 명 자리가 있나요?"
    },
    {
      "text": "我想請問你們的診所有看感冒嗎？",
      "pinyin": "Wǒ xiǎng qǐngwèn nǐmen de zhěnsuǒ yǒu kàn gǎnmào ma?",
      "pinyin_numeric": "wo3 xiang3 qing3wen4 ni3men de zhen3suo3 you3 kan4 gan3mao4 ma0?",
      "translation_en": "I'd like to ask if your clinic treats colds.",
      "translation_ko": "감기 진료를 하나요?"
    }
  ]
}
